// src/components/fretboard/TablatureDisplay.tsx

import React from 'react';
import { type LickNote } from '../../services/AIEngine';

interface TablatureDisplayProps {
  notes: LickNote[];
  activeStep?: number;
  isGenerating?: boolean;
  height?: number;
  noteSpacing?: number;
  showStrings?: boolean;
  showFretNumbers?: boolean;  // ← ВОССТАНАВЛИВАЕМ!
  compact?: boolean;
}

const TablatureDisplay: React.FC<TablatureDisplayProps> = ({
  notes,
  activeStep = -1,
  isGenerating = false,
  height = 180,
  noteSpacing = 70,
  showStrings = true,
  showFretNumbers = true,  // ← ВОССТАНАВЛИВАЕМ! по умолчанию true
  compact = false
}) => {
  const stringSpacing = compact ? 16 : 20;
  const startY = compact ? 30 : 40;
  const startX = compact ? 60 : 80;
  const noteSize = compact ? 20 : 24;

  if (!notes || notes.length === 0) {
    return (
      <div style={{ 
        color: 'var(--text-muted)', 
        fontWeight: 800, 
        fontSize: '12px', 
        textAlign: 'center',
        padding: '20px'
      }}>
        Нет нот для отображения
      </div>
    );
  }

  const svgWidth = Math.max(compact ? 500 : 800, notes.length * noteSpacing + (compact ? 100 : 150));
  const svgHeight = height;

  return (
    <svg 
      viewBox={`0 0 ${svgWidth} ${svgHeight}`} 
      style={{ 
        width: '100%', 
        minWidth: compact ? '400px' : '600px', 
        height: `${height}px`, 
        display: 'block' 
      }}
    >
      {/* Линии струн */}
      {[0, 1, 2, 3, 4, 5].map((strIndex) => (
        <line 
          key={`str-${strIndex}`}
          x1="30" y1={startY + strIndex * stringSpacing} 
          x2={svgWidth - 30} y2={startY + strIndex * stringSpacing} 
          stroke="rgba(255,255,255,0.1)" 
          strokeWidth={strIndex === 0 || strIndex === 5 ? '2' : '1.5'} 
        />
      ))}

      {/* Обозначения струн */}
      {showStrings && ['e', 'B', 'G', 'D', 'A', 'E'].map((note, i) => (
        <text 
          key={`tune-${i}`} 
          x="45" 
          y={startY + i * stringSpacing + 4} 
          fill="var(--text-muted)" 
          fontSize={compact ? "10" : "12"} 
          fontWeight="800" 
          fontFamily="monospace" 
          textAnchor="middle"
        >
          {note}
        </text>
      ))}

      {/* Вертикальные линии */}
      <line x1="70" y1={startY} x2="70" y2={startY + 5 * stringSpacing} stroke="var(--text-muted)" strokeWidth="2" />
      <line 
        x1={svgWidth - 30} 
        y1={startY} 
        x2={svgWidth - 30} 
        y2={startY + 5 * stringSpacing} 
        stroke="var(--text-muted)" 
        strokeWidth="2" 
      />

      {/* Отрисовка нот */}
      {notes.map((note: LickNote, index: number) => {
        if (note.isRest) {
          const x = startX + index * noteSpacing;
          return (
            <g key={`rest-${index}`}>
              <text x={x} y={startY + 5 * stringSpacing + 20} fill="var(--text-muted)" fontSize={compact ? "10" : "12"} fontFamily="monospace" textAnchor="middle">𝄐</text>
            </g>
          );
        }

        const x = startX + index * noteSpacing;
        const y = startY + note.string * stringSpacing;
        const nextNote = notes[index + 1];
        const nextX = startX + (index + 1) * noteSpacing;
        const nextY = startY + (nextNote?.string || 0) * stringSpacing;
        
        const stemBottomY = compact ? startY + 5 * stringSpacing + 10 : startY + 5 * stringSpacing + 30;
        const isActive = activeStep === index;
        const isAccent = note.accent;
        const isLegato = note.technique === 'hammer' || note.technique === 'pull';
        const isMuted = note.technique === 'mute';
        
        return (
          <g key={`note-${index}`} style={{ opacity: isGenerating ? 0.3 : 1, transition: 'all 0.1s' }}>
            
            {note.tiedToNext && nextNote && (
              <path 
                d={`M ${x + 6} ${y - 12} Q ${(x + nextX) / 2} ${Math.min(y, nextY) - 25} ${nextX - 6} ${nextY - 12}`} 
                fill="transparent" 
                stroke={isActive ? "var(--accent)" : "var(--text-muted)"} 
                strokeWidth="1.5"
              />
            )}

            {isLegato && (
              <text x={x} y={y - 22} fill="var(--accent)" fontSize={compact ? "9" : "11"} fontWeight="900" fontFamily="monospace" textAnchor="middle">
                {note.technique === 'hammer' ? 'H' : 'P'}
              </text>
            )}

            {note.technique === 'slide' && nextNote && (
              <line x1={x + 12} y1={y - 8} x2={nextX - 12} y2={nextY + 8} stroke="var(--accent)" strokeWidth="2" opacity="0.7" />
            )}

            {note.technique === 'vibrato' && (
              <path 
                d={`M ${x-10} ${y-20} Q ${x-5} ${y-25} ${x} ${y-20} T ${x+10} ${y-20} T ${x+20} ${y-20}`} 
                fill="transparent" 
                stroke="var(--accent)" 
                strokeWidth="2" 
              />
            )}

            {note.technique === 'bend' && (
              <path 
                d={`M ${x} ${y-20} Q ${x+5} ${y-30} ${x+15} ${y-20}`} 
                fill="transparent" 
                stroke="var(--accent)" 
                strokeWidth="2" 
              />
            )}

            {note.technique === 'ghost' && (
              <text x={x} y={y - 20} fill="var(--text-muted)" fontSize={compact ? "8" : "10"} fontFamily="monospace" textAnchor="middle">( )</text>
            )}

            {isAccent && (
              <text x={x} y={y - 28} fill="var(--accent)" fontSize={compact ? "12" : "14"} fontWeight="900" textAnchor="middle">›</text>
            )}

            {!compact && (
              <line 
                x1={x} y1={y + 10} 
                x2={x} y2={stemBottomY} 
                stroke={isActive ? "var(--accent)" : "var(--text-muted)"} 
                strokeWidth="1.5" 
              />
            )}
            
            {!compact && (note.duration === 'eighth' || note.duration === 'sixteenth' || note.duration === 'dotted_eighth') && (
              <line 
                x1={x} y1={stemBottomY} 
                x2={x + 15} y2={stemBottomY - 5} 
                stroke={isActive ? "var(--accent)" : "var(--text-muted)"} 
                strokeWidth="2" 
              />
            )}
            {!compact && note.duration === 'sixteenth' && (
              <line 
                x1={x} y1={stemBottomY - 6} 
                x2={x + 15} y2={stemBottomY - 11} 
                stroke={isActive ? "var(--accent)" : "var(--text-muted)"} 
                strokeWidth="2" 
              />
            )}

            {!compact && note.duration === 'whole' && (
              <circle 
                cx={x} cy={y + 8} 
                r="6" 
                fill="none" 
                stroke={isActive ? "var(--accent)" : "var(--text-muted)"} 
                strokeWidth="1.5" 
              />
            )}

            <rect 
              x={x - noteSize/2} 
              y={y - noteSize/2} 
              width={noteSize} 
              height={noteSize} 
              fill={isMuted ? 'rgba(255,255,255,0.05)' : '#111216'} 
              rx="4" 
            />

            {isActive && (
              <circle 
                cx={x} cy={y} r={noteSize/2 + 4} 
                fill="var(--accent)" 
                opacity="0.8" 
                style={{ filter: 'drop-shadow(0 0 12px var(--accent))' }} 
              />
            )}

            {/* ✅ ИСПОЛЬЗУЕМ showFretNumbers - показываем номер лада только если включено */}
            {showFretNumbers && (
              <text 
                x={x} y={y + 5} 
                fill={isActive ? '#000' : (isLegato ? 'var(--accent)' : (note.technique !== 'none' && note.technique !== 'mute' ? 'var(--accent)' : 'var(--text-primary)'))} 
                fontSize={isActive ? (compact ? "16" : "18") : (isAccent ? (compact ? "14" : "16") : (compact ? "12" : "14"))} 
                fontWeight={isAccent ? 900 : 800} 
                fontFamily="monospace" 
                textAnchor="middle"
              >
                {isMuted ? '×' : note.fret}
              </text>
            )}

            {/* ✅ Если showFretNumbers выключен - показываем точку или кружок */}
            {!showFretNumbers && (
              <circle 
                cx={x} cy={y} 
                r={isActive ? 12 : 6} 
                fill={isActive ? "var(--accent)" : "rgba(255,255,255,0.3)"} 
                opacity={isActive ? 1 : 0.5}
              />
            )}
          </g>
        );
      })}
    </svg>
  );
};

export default TablatureDisplay;